import org.junit.jupiter.api.Test;
import java.util.Arrays;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void basic() {
        int[] nums = {3, 2, 2, 3};
        int k = new Solution().removeElement(nums, 3);
        assertEquals(2, k);
        int[] kept = Arrays.copyOfRange(nums, 0, k);
        Arrays.sort(kept);
        assertArrayEquals(new int[]{2, 2}, kept);
    }

    @Test
    void noMatchingElements() {
        int[] nums = {1, 2, 3, 4};
        int k = new Solution().removeElement(nums, 7);
        assertEquals(4, k);
        int[] kept = Arrays.copyOfRange(nums, 0, k);
        Arrays.sort(kept);
        assertArrayEquals(new int[]{1, 2, 3, 4}, kept);
    }

    @Test
    void allMatch() {
        int[] nums = {5, 5, 5};
        int k = new Solution().removeElement(nums, 5);
        assertEquals(0, k);
    }

    @Test
    void single_match() {
        int[] nums = {9};
        int k = new Solution().removeElement(nums, 9);
        assertEquals(0, k);
    }

    @Test
    void single_no_match() {
        int[] nums = {9};
        int k = new Solution().removeElement(nums, 1);
        assertEquals(1, k);
        int[] kept = Arrays.copyOfRange(nums, 0, k);
        assertArrayEquals(new int[]{9}, kept);
    }

    @Test
    void empty() {
        int[] nums = {};
        int k = new Solution().removeElement(nums, 0);
        assertEquals(0, k);
    }

    @Test
    void mixedValues() {
        // adversarial: val interspersed, multiple distinct remaining values
        int[] nums = {0, 1, 2, 2, 3, 0, 4, 2};
        int k = new Solution().removeElement(nums, 2);
        assertEquals(5, k);
        int[] kept = Arrays.copyOfRange(nums, 0, k);
        Arrays.sort(kept);
        assertArrayEquals(new int[]{0, 0, 1, 3, 4}, kept);
    }
}
